class Solution:
    def numberOfPowerfulInt(self, start: int, finish: int, limit: int, s: str) -> int:
        from itertools import product

        def is_valid(num: int) -> bool:
            s_num = str(num)
            if not s_num.endswith(s):
                return False
            for ch in s_num:
                if int(ch) > limit:
                    return False
            return True

        count = 0
        for num in range(start, finish + 1):
            if is_valid(num):
                count += 1
        return count
